import torch
def tricky(tokens):
    lp = torch.full((6,), -100.0)
    if len(tokens) == 1:
        lp[1] = -1.0; lp[2] = -0.5
    elif tokens[-1] == 1:
        lp[5] = 0.0
    elif tokens[-1] == 2:
        lp[5] = -10.0
    else:
        lp[5] = 0.0
    return lp
seq = {fn}(tricky, start_token=0, max_len=5, beam_width=2, eos_token=5)
assert seq == [0, 1, 5], f'Beam should find [0,1,5], got {seq}'

lrs = [{fn}(step=i, total_steps=100, warmup_steps=10, max_lr=0.001) for i in range(11)]
for i in range(len(lrs) - 1):
    assert lrs[i] <= lrs[i+1] + 1e-10, f'Not increasing at step {i}'
